import{createDesmosGraphs,desmosColors}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";export default function(){createDesmosGraphs({unitCircle3D:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-1.5,xmax:1.5,ymin:-1.5,ymax:1.5,zmin:-1.5,zmax:1.5},expressions:[{latex:raw`x^2 + y^2 \leq 1 \{z = 0\}`,color:desmosColors.purple,secret:!0},{latex:raw`s(t) = (\cos(t), \sin(t), 0)`,secret:!0},{latex:raw`s(t)`,color:desmosColors.blue,parametricDomain:{min:0,max:"2\\pi"},secret:!0},{latex:raw`T = [\frac{\pi}{4}, \frac{3\pi}{4}, \frac{5\pi}{4}, \frac{7\pi}{4}]`,secret:!0},{latex:raw`\vector(s(T), s(T) + 0.2\frac{s'(T)}{\left| s'(T) \right|})`,lineWidth:10,color:desmosColors.blue,secret:!0}]},sphereCap:{use3d:!0,options:{showPlane3D:!1},bounds:{xmin:-.5,xmax:1.5,ymin:-1,ymax:1,zmin:-1,zmax:1},expressions:[{latex:raw`x^2 + y^2 + z^2 = 1 \{ x \geq 0.65 \}`,color:desmosColors.purple,secret:!0},{latex:raw`s(t) = (0.65, \sqrt{1 - 0.65^2}\cos(t), \sqrt{1 - 0.65^2}\sin(t))`,secret:!0},{latex:raw`s(t)`,color:desmosColors.blue,parametricDomain:{min:0,max:"2\\pi"},secret:!0},{latex:raw`T = [\frac{\pi}{4}, \frac{3\pi}{4}, \frac{5\pi}{4}, \frac{7\pi}{4}]`,secret:!0},{latex:raw`\vector(s(T), s(T) + 0.15\frac{s'(T)}{\left| s'(T) \right|})`,lineWidth:10,color:desmosColors.blue,secret:!0},{latex:raw`P = [(\cos(i), \sin(i)\cos(j), \sin(i)\sin(j)) \for i = [0, 0.375, 0.7], j = [0, \frac{\pi}{4}, ..., 2\pi]]`,hidden:!0,secret:!0},{latex:raw`\vector(P, 1.2P)`,color:desmosColors.red,secret:!0}]}})}